<?php require 'vendor/autoload.php'; $app = require_once 'bootstrap/app.php'; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); $props = App\Models\Property::where('user_id', 1)->get(); foreach($props as $p) { foreach($p->photos as $photo) { if ($photo->photo_path) \Illuminate\Support\Facades\Storage::disk('public')->delete($photo->photo_path); $photo->delete(); } App\Models\Favorite::where('property_id', $p->id)->delete(); App\Models\Review::where('property_id', $p->id)->delete(); $p->delete(); } echo 'Deleted ' . $props->count() . ' fake properties.'; ?>
